class Solution {
public:

    // Check if substring s[l...r] is palindrome
    bool isPalindrome(const string &s, int l, int r) {
        while (l < r) {
            if (s[l] != s[r]) return false;
            l++; r--;
        }
        return true;
    }

    // Backtracking to generate all partitions
    void generate(int index, const string &s, vector<string> &path, vector<vector<string>> &result) {
        if (index == s.size()) {
            result.push_back(path);
            return;
        }

        for (int end = index; end < s.size(); end++) {
            if (isPalindrome(s, index, end)) {
                path.push_back(s.substr(index, end - index + 1));
                generate(end + 1, s, path, result);
                path.pop_back();
            }
        }
    }

    vector<vector<string>> partitionString(string inputString) {
        vector<vector<string>> result;
        vector<string> path;
        generate(0, inputString, path, result);
        return result;
    }
};

