void generate(int index, char *s,
              char current[][MAXN], int curSize,
              void (*callback)(char current[][MAXN], int curSize)) 
{
    int n = strlen(s);

    if (index == n) {
        callback(current, curSize);
        return;
    }

    for (int end = index; end < n; end++) {
        if (isPalindrome(s, index, end)) {
            int len = end - index + 1;
            strncpy(current[curSize], s + index, len);
            current[curSize][len] = '\0';

            generate(end + 1, s, current, curSize + 1, callback);
        }
    }
}

void partitionString(char *inputString,
                     void (*callback)(char arr[][MAXN], int size)) 
{
    char current[MAXN][MAXN];
    generate(0, inputString, current, 0, callback);
}

