class Solution {

    // Check if substring s[l...r] is palindrome
    private boolean isPalindrome(String s, int l, int r) {
        while (l < r) {
            if (s.charAt(l) != s.charAt(r)) return false;
            l++;
            r--;
        }
        return true;
    }

    // Backtracking to generate all palindrome partitions
    private void backtrack(int index, String s, List<String> path, List<List<String>> result) {
        if (index == s.length()) {
            result.add(new ArrayList<>(path));
            return;
        }

        for (int end = index; end < s.length(); end++) {
            if (isPalindrome(s, index, end)) {
                path.add(s.substring(index, end + 1));
                backtrack(end + 1, s, path, result);
                path.remove(path.size() - 1);
            }
        }
    }

    public List<List<String>> partitionString(String inputString) {
        List<List<String>> result = new ArrayList<>();
        backtrack(0, inputString, new ArrayList<>(), result);
        return result;
    }
}

