class Solution {
    // Check if substring s[l...r] is a palindrome
    isPalindrome(s, l, r) {
        while (l < r) {
            if (s[l] !== s[r]) return false;
            l++;
            r--;
        }
        return true;
    }

    // Backtracking DFS
    backtrack(index, s, path, result) {
        if (index === s.length) {
            result.push([...path]);
            return;
        }

        for (let end = index; end < s.length; end++) {
            if (this.isPalindrome(s, index, end)) {
                path.push(s.substring(index, end + 1));
                this.backtrack(end + 1, s, path, result);
                path.pop();
            }
        }
    }

    partitionString(inputString) {
        const result = [];
        this.backtrack(0, inputString, [], result);
        return result;
    }
}
